const kpis = $('Query Dashboard KPIs').item.json;
const timeSeries = $('Query Revenue Time Series').all().map(i => i.json);
const traffic = $('Query Traffic Sources').all().map(i => i.json);

return {
  json: {
    totalRevenue: parseFloat(kpis.total_revenue),
    totalOrders: parseInt(kpis.total_orders),
    aov: parseFloat(kpis.aov),
    pageViews: parseInt(kpis.page_views),
    conversionRate: parseFloat(kpis.conversion_rate),
    returningCustomerRate: parseFloat(kpis.returning_rate),
    revenueTimeSeries: timeSeries,
    topTrafficSources: traffic,
    liveVisitors: Math.floor(Math.random() * 50) + 10
  }
};
